INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('13', '1', 'Metro Exodus — Gold Edition', 'metro-exodus-gold', '275', NULL, 'Steam', 'Экшен', 'Постапокалиптический шутер от первого лица по мотивам романов Дмитрия Глуховского. Исследуйте обширные локации России и Казахстана на поезде «Аврора», сражайтесь с мутантами и мародёрами, выбирайте тактику скрытности или лобового боя. Gold Edition включает все сюжетные DLC («Самовар», «Весной» и «Два полковника»). Ключ Steam Region Free, мгновенная доставка на email.', 'metro-exodus-gold.jpg', '1', '1', '0', '2026-05-15 20:45:07', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('14', '1', 'HELLDIVERS 2', 'helldivers-2', '1999', '3999', 'Steam', 'Экшен', 'Кооперативный шутер от третьего лица на четырёх игроков от Arrowhead Game Studios. Выполняйте опасные миссии на враждебных планетах, отбивайте вторжения инопланетян и координируйте удары орбитального оружия — дружественный огонь здесь не редкость. Динамичные бои, кастомизация доспехов и постоянные обновления контента. Цифровой ключ Steam с активацией в вашем регионе.', 'helldivers-2.jpg', '1', '1', '0', '2026-05-15 20:45:07', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('15', '1', 'Resident Evil 4 — Gold Edition', 'resident-evil-4-gold', '2599', NULL, 'Steam', 'Хоррор', 'Полноценный ремейк культового хоррор-экшена 2004 года с современной графикой и переработанным геймплеем. Агент Леон Кеннеди спасает дочь президента из европейской деревни, заражённой паразитами. Gold Edition включает режим «Кровавые деньги» Separate Ways и режим Mercenaries. Напряжённые бои, головоломки и атмосфера survival horror. Ключ Steam, доставка сразу после оплаты.', 'resident-evil-4-gold.jpg', '1', '0', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('16', '2', 'Elden Ring: Nightreign', 'elden-ring-nightreign', '2299', NULL, 'Steam', 'RPG', 'Кооперативное приключение во вселенной Elden Ring от FromSoftware на троих игроков. Каждые три дня мир поглощает катастрофа — вам предстоит выжить три ночи, исследуя процедурно меняющиеся земли Лимгрейва. Уникальные герои с особыми способностями, совместные боссы и напряжённые рогалик-сессии. Отдельная история в духе souls-like. Лицензионный ключ Steam.', 'elden-ring-nightreign.jpg', '1', '1', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('17', '2', 'Kingdom Come: Deliverance II — Royal Edition', 'kingdom-come-deliverance-2', '2299', NULL, 'Steam', 'RPG', 'Продолжение реалистичной средневековой RPG от Warhorse Studios. Генрих Шкодержевед продолжает путь в XV веке: политические интриги, честные поединки на мечах, репутация и выживание без магии. Royal Edition включает все DLC и бонусный контент. Глубокий сюжет, открытый мир и историческая достоверность. Ключ активации Steam.', 'kingdom-come-deliverance-2.jpg', '1', '0', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('18', '2', 'Dragon''s Dogma 2', 'dragons-dogma-2', '1999', NULL, 'Steam', 'RPG', 'Масштабная экшен-RPG с открытым миром от Capcom. Создайте героя-Arisen, сражайтесь с гигантскими драконами, используя систему «взбирания» на врагов, и командуйте пешками — ИИ-спутниками с уникальными классами. Два обширных королевства, динамичные квесты и свобода билдов. Полная версия для Steam. Мгновенная выдача ключа после оплаты.', 'dragons-dogma-2.jpg', '1', '0', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('19', '3', 'Hearts of Iron IV: Cadet Edition', 'hearts-of-iron-4', '775', NULL, 'Steam', 'Стратегия', 'Глобальная стратегия Второй мировой войны от Paradox Interactive. Управляйте любой нацией 1936–1948 годов: дипломатия, промышленность, исследования и масштабные фронты. Cadet Edition — базовая версия, идеальная для знакомства с серией; DLC приобретаются отдельно. Глубокий симулятор войны с тысячами модов в Workshop. Ключ Steam.', 'hearts-of-iron-4.jpg', '1', '0', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('20', '3', 'Stellaris — Anniversary Edition', 'stellaris-anniversary', '3495', NULL, 'Steam', 'Стратегия', 'Космическая гранд-стратегия 4X в реальном времени: исследуйте галактику, колонизируйте планеты, встречайте инопланетные империи и ведите войны за звёзды. Anniversary Edition включает базовую игру и набор стартового DLC. Процедурные карты, кастомные расы и бесконечные сценарии «а что, если». Ключ Steam с быстрой доставкой.', 'stellaris-anniversary.jpg', '1', '0', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('21', '3', 'Heroes of Might and Magic: Olden Era', 'heroes-might-magic-olden-era', '995', NULL, 'Steam', 'Стратегия', 'Возрождение легендарной пошаговой стратегии Heroes of Might and Magic. Исследуйте карту, захватывайте ресурсы, нанимайте армии и сражайтесь в тактических боях на гексагональном поле. Новые фракции, герои и сюжетная кампания в духе классики. Для поклонников HoMM III и V. Цифровой ключ Steam.', 'heroes-might-magic-olden-era.jpg', '1', '1', '0', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('22', '4', 'Gothic 1 Remake', 'gothic-1-remake', '2495', NULL, 'Steam', 'RPG', 'Предзаказ полноценного ремейка культовой RPG 2001 года от THQ Nordic и Alkimia Interactive. Обновлённая графика, современное управление и знакомый мир Нижней и Внешней долины с тремя лагерями и жёсткими моральными выборами. Ключ будет отправлен на email в день релиза Steam. Гарантия активации и поддержка при предзаказе.', 'gothic-1-remake.jpg', '1', '0', '1', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('23', '4', 'Directive 8020 — Digital Deluxe', 'directive-8020-deluxe', '3999', NULL, 'Steam', 'Приключения', 'Интерактивный хоррор-триллер от Supermassive Games — духовный наследник Until Dawn и The Quarry. Космическая колония сталкивается с инопланетной угрозой, а решения игрока определяют, кто выживет. Digital Deluxe включает бонусные эпизоды и косметику. Кинематографическая подача и кооперативный режим. Предзаказ: ключ в день выхода.', 'directive-8020-deluxe.jpg', '1', '0', '1', '2026-05-15 20:45:08', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('24', '1', 'Dark Souls III — Deluxe Edition', 'dark-souls-3-deluxe', '2999', NULL, 'Steam', 'Экшен', 'Заключительная часть трилогии souls-like от FromSoftware. Исследуйте королевство Лотрик, сражайтесь с эпическими боссами и собирайте души для прокачки. Deluxe Edition включает базовую игру и Season Pass с DLC Ashes of Ariandel и The Ringed City. Высокая сложность, точный бой и богатый лор. Ключ Steam, мгновенная доставка.', 'dark-souls-3-deluxe.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('25', '2', 'Baldur''s Gate 3', 'baldurs-gate-3', '2999', NULL, 'Steam', 'RPG', 'Масштабная RPG по правилам D&D 5-й редакции от Larian Studios — победитель The Game Awards. Создайте отряд из уникальных спутников, принимайте решения с последствиями на весь сюжет, сражайтесь в пошаговых тактических боях. Кооператив до 4 игроков, сотни часов контента и свобода прохождения. Полная версия для Steam. Ключ приходит на почту сразу после оплаты.', 'baldurs-gate-3.jpg', '1', '1', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('26', '2', 'Cyberpunk 2077', 'cyberpunk-2077', '1499', NULL, 'Steam', 'RPG', 'Открытый мир Night City от CD PROJEKT RED — киберпанк-RPG с видом от первого лица. Играйте за V, прокачивайте импланты, выполняйте заказы и раскрывайте заговоры корпораций. Обновление 2.0 и дополнение Phantom Liberty значительно расширили контент. Глубокий сюжет, стильная атмосфера и свобода стиля прохождения. Лицензионный ключ Steam.', 'cyberpunk-2077.jpg', '1', '1', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('27', '1', 'Black Myth: Wukong', 'black-myth-wukong', '3599', NULL, 'Steam', 'Экшен', 'Экшен-RPG по мотивам «Путешествия на Запад» от Game Science — один из главных хитов Steam 2024 года. Играйте за Послушника, осваивайте трансформации и сражайтесь с мифическими боссами в духе souls-like. Потрясающая визуальная подача на Unreal Engine 5 и кинематографические кат-сцены. Ключ Steam Region Free.', 'black-myth-wukong.jpg', '1', '1', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('28', '1', 'Grand Theft Auto V', 'gta-v', '999', NULL, 'Steam', 'Экшен', 'Легендарный криминальный экшен от Rockstar Games в Лос-Сантосе. Три протагониста, ограбления, открытый мир и режим GTA Online с регулярными обновлениями. Сотни часов контента: гонки, бизнесы, хейсты и PvP. Версия для Steam включает доступ к GTA Online. Цифровой ключ с мгновенной активацией.', 'gta-v.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('29', '1', 'Red Dead Redemption 2', 'red-dead-redemption-2', '1999', NULL, 'Steam', 'Экшен', 'Эпический вестерн от Rockstar Games о банде Ван дер Линде в упадке Дикого Запада. Огромный живой мир, охота, дуэли, честь и драматический сюжет Артура Моргана. Один из самых детализированных open-world проектов в истории. Red Dead Online включён. Ключ Steam, доставка на email в течение минут.', 'red-dead-redemption-2.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('30', '2', 'Hogwarts Legacy', 'hogwarts-legacy', '1299', NULL, 'Steam', 'RPG', 'Открытый мир волшебства в Хогвартсе XIX века. Создайте студента, посещайте уроки заклинаний, исследуйте замок и окрестности, сражайтесь с тёмными магами и раскрывайте древнюю тайну. RPG с прокачкой, полётами на метле и богатой коллекцией заклинаний. Официальная лицензия Wizarding World. Ключ Steam.', 'hogwarts-legacy.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('31', '1', 'Palworld', 'palworld', '999', NULL, 'Steam', 'Выживание', 'Мультиплеерное выживание с крафтом и сбором существ-палов. Стройте базы, разводите палов для работы и боя, исследуйте остров и сражайтесь с боссами. Кооператив до 4 игроков на одном сервере, PvP-режимы и постоянные обновления контента. Смесь survival, строительства и коллекционирования. Ключ Steam.', 'palworld.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('32', '2', 'The Witcher 3: Wild Hunt — GOTY', 'witcher-3-goty', '399', NULL, 'Steam', 'RPG', 'Game of the Year Edition — полное издание культовой RPG от CD PROJEKT RED. Охотник на чудовищ Геральт ищет Цири в войне, наполненной мирами, моральными дилеммами и сотнями квестов. Включены дополнения «Каменные сердца» и «Кровь и вино». Один из лучших сюжетов в жанре. Ключ Steam по выгодной цене.', 'witcher-3-goty.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('33', '1', 'Sekiro: Shadows Die Twice', 'sekiro', '2499', NULL, 'Steam', 'Экшен', 'Экшен от FromSoftware в феодальной Японии. Мастерски отрабатывайте парирования, используйте протез-руку с различными гаджетами и сражайтесь с легендарными боссами. Акцент на точном тайминге, а не на прокачке уровня. Лауреат Game of the Year 2019. Ключ Steam, мгновенная доставка.', 'sekiro.jpg', '1', '0', '0', '2026-05-15 20:45:09', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('34', '1', 'Hades II', 'hades-2', '849', NULL, 'Steam', 'Roguelike', 'Продолжение хита Hades от Supergiant Games в жанре roguelike. Играйте за Мелиною, колдунью и принцессу Аида, сражайтесь с хтоническими богами и оттачивайте билды в процедурных забегах. Блестящий сценарий, озвучка и визуальный стиль. Ранний доступ с регулярными крупными обновлениями. Ключ Steam.', 'hades-2.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('35', '1', 'Monster Hunter: World', 'monster-hunter-world', '499', NULL, 'Steam', 'Экшен', 'Охота на гигантских монстров в кооперативе до 4 игроков. Собирайте ресурсы, крафтите оружие и броню из частей трофеев, изучайте повадки каждого вида. Обширный мир и дополнение Iceborne (приобретается отдельно). Идеальная точка входа в серию Monster Hunter. Ключ Steam.', 'monster-hunter-world.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('36', '1', 'Lies of P', 'lies-of-p', '1999', NULL, 'Steam', 'Souls-like', 'Souls-like в стилистике тёмного Пиноккио — Белый замок Крата и механические куклы. Гибкая система оружия, ложные воспоминания и моральные выборы влияют на концовку. Высокие оценки игроков Steam за боевую систему и атмосферу. От создателей, вдохновлённых Bloodborne. Ключ активации Steam.', 'lies-of-p.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('37', '1', 'Warhammer 40,000: Space Marine 2', 'space-marine-2', '2499', '3999', 'Steam', 'Экшен', 'Масштабный кооперативный шутер от третьего лица во вселенной Warhammer 40,000. Капитан Титус сражается с ордами тиранидов в режиме «мясорубки» на троих игроков. Кинематографичные сцены, прокачка и PvP-режим Eternal War. Для фанатов 40k и экшен-серий. Ключ Steam с быстрой выдачей.', 'space-marine-2.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('38', '1', 'Rust', 'rust', '699', '1299', 'Steam', 'Выживание', 'Хардкорное мультиплеерное выживание на острове: собирайте ресурсы, стройте базы, рейдьте соседей и защищайтесь от других игроков. PvP-ориентированный геймплей, вайпы серверов и постоянная напряжённость. Один из самых популярных survival-проектов Steam. Требуется подключение к интернету. Ключ Steam.', 'rust.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('39', '1', 'Valheim', 'valheim', '349', NULL, 'Steam', 'Выживание', 'Викингское выживание с кооперативом до 10 игроков. Исследуйте процедурный мир, стройте длинные дома, побеждайте мифических боссов и крафтите экипировку эпохи викингов. Спокойное строительство сочетается с эпичными сражениями. Отличный выбор для игры с друзьями. Ключ Steam по низкой цене.', 'valheim.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('40', '1', 'Terraria', 'terraria', '249', NULL, 'Steam', 'Песочница', '2D-песочница с бесконечным контентом: копайте, стройте, сражайтесь с боссами и исследуйте подземелья. Сотни предметов, NPC, события и режим Master Mode. Кооператив и локальный мультиплеер. Один из самых продаваемых инди-хитов Steam за всю историю. Ключ доставляется мгновенно.', 'terraria.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('41', '3', 'RimWorld', 'rimworld', '649', NULL, 'Steam', 'Симулятор', 'Колоний-симулятор с процедурными историями: управляйте выжившими на чужой планете, стройте базу, лечите раны и отражайте рейды. Уникальный ИИ-рассказчик создаёт драму из случайных событий. Глубокая моддинг-сцена. Для любителей Dwarf Fortress и survival-стратегий. Ключ Steam.', 'rimworld.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('42', '3', 'Cities: Skylines II', 'cities-skylines-2', '1999', NULL, 'Steam', 'Симулятор', 'Градостроительный симулятор нового поколения от Colossal Order. Проектируйте дороги, зонирование, транспорт и экономику растущего мегаполиса с реалистичной симуляцией. Улучшенная графика и масштаб по сравнению с первой частью. Для любителей SimCity и градостроения. Ключ Steam.', 'cities-skylines-2.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('43', '2', 'Fallout 4', 'fallout-4', '499', NULL, 'Steam', 'RPG', 'Постапокалиптическая RPG от Bethesda в Содружестве. Ищите сына после ядерной войны, стройте поселения, модифицируйте оружие и исследуйте руины Бостона. Система VATS, фракции и сотни часов побочного контента. Один из столпов серии Fallout. Ключ Steam Game of the Year Edition (базовая версия).', 'fallout-4.jpg', '1', '0', '0', '2026-05-15 20:45:10', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('46', '1', 'Devil May Cry 5', 'devil-may-cry-5', '999', NULL, 'Steam', 'Экшен', 'Стильный слэшер от Capcom с тремя играбельными героями и динамичной боевой системой. Комбо, ранги стиля и эпичные боссы в демоническом Нижнем городе. Кооператив Ghost Mode после прохождения. Один из лучших экшенов последних лет по отзывам Steam. Лицензионный ключ с мгновенной доставкой.', 'devil-may-cry-5.jpg', '1', '0', '0', '2026-05-15 21:29:54', '2026-05-21 23:21:28');
INSERT INTO "products" ("id", "category_id", "name", "slug", "price", "old_price", "platform", "genre", "description", "image", "available", "is_featured", "is_preorder", "created_at", "updated_at") VALUES ('47', '2', 'Starfield', 'starfield', '2999', NULL, 'Steam', 'RPG', 'Космическая RPG от Bethesda Game Studios: исследуйте сотни планет, стройте корабли, вступайте во фракции и создавайте собственную историю среди звёзд. Глубокая кастомизация персонажа, баз на планетах и сюжетные квесты. Новая вселенная от авторов The Elder Scrolls и Fallout. Ключ Steam Region Free.', 'starfield.jpg', '1', '0', '0', '2026-05-15 21:29:54', '2026-05-21 23:21:28');
